#!/usr/bin/env bash
# workflow-1.sh — 一个个案从接案评估到结案的完整弧线 SOP walkthrough for 心理咨询 / 心理治疗(临床实践者视角 — 接案与评估 / 个案概念化 / 主流流派技术(CBT 与第三浪潮 / 精神动力 / 人本存在 / 家庭系统 / 创伤治疗) / 伦理边界与危机干预 / 督导与个人成长 / 执业形态与经营 — 涵盖中国大陆行业现状 + 欧美持照体系,两套体系差异极大).
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="心理咨询 / 心理治疗(临床实践者视角 — 接案与评估 / 个案概念化 / 主流流派技术(CBT 与第三浪潮 / 精神动力 / 人本存在 / 家庭系统 / 创伤治疗) / 伦理边界与危机干预 / 督导与个人成长 / 执业形态与经营 — 涵盖中国大陆行业现状 + 欧美持照体系,两套体系差异极大)"
WORKFLOW="一个个案从接案评估到结案的完整弧线"

usage() {
  cat <<EOF
workflow-1.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./workflow-1.sh             # interactive
  ./workflow-1.sh --dry-run
  ./workflow-1.sh --json
  ./workflow-1.sh --explain
  ./workflow-1.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "一个个案从接案评估到结案的完整弧线" 工作流。

一句话: 把一个来访者从「第一次联系 / 初始访谈」一路带到「计划性结案」——经过风险评估、个案概念化、治疗计划、工作期、结案，是这一行最大尺度的工作流。

入门 SOP 共 6 步, 失败模式自检 5 项。

相关心智模型:
  • 治疗关系 / 共同要素 > 单一技术: 这一行的资深人默认「治疗关系的质量、共情、期望、来访者因素」这些**跨流派共有的共同要素**对疗效的解释力,可能不亚于任一流派的特定技术 —— 所以「学对了流派」从来不够,「谁来做、和来访者建立了什么
  • 症状是有功能 / 是适应,不是单纯的「病」: 这一行的人看一个症状,默认先问「它在为这个人 / 这个系统**做什么**」—— 症状常是某个困境下能找到的最优解、是适应而非缺陷,去病理化地理解它,比急着「消除」它更接近治疗。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**初始访谈 / intake（第 1–2 次会谈）**：建立初步关系、收集主诉与相关史（症状、发展史、关系、家庭、医疗、用药、既往治疗）、签**知情同意**（含保密及其法定例外、收费、设置、远程的特殊条款）。**输出**=一份 intake 记录 + 已签知情同意。"
  "**风险评估（与 intake 同步，且贯穿全程）**：评估自杀 / 自伤 / 对他人危险 / 受虐 / 急性精神病性等风险——用结构化工具（如 C-SSRS）问到位。**风险评估不是一次性动作，是每次会谈都要扫的**。详见 W4。"
  "**个案概念化（第 2–4 次会谈逐步成形）**：把症状 / 史 / 关系 / 情境组织成一个「为什么这个人现在这样、什么在维持、从哪入手」的可工作理解。详见 W3。**输出**=一份初步个案概念化（动态、可修订的工作假设，不是诊断标签）。"
  "**治疗计划（第 2–4 次，与概念化同步）**：基于概念化定治疗目标、大致方法、频率、预估时长，和来访者协商达成一致（目标 + 任务的协商本身就是治疗联盟的一部分）。必要时查循证清单（APA Div12 / NICE）看「这个障碍证据指向哪些选项」。"
  "**工作期（多次会谈，数周到数年不等）**：按 W1 的单次结构反复推进；定期回看概念化与计划是否仍成立；处理治疗联盟的**破裂与修复**（rupture & repair）；遇到瓶颈重新概念化。"
  "**结案（calculated ending，理想是计划性的）**：识别「目标基本达成 / 来访者准备好 / 或需要转介」的信号，留出**结案阶段**（不是突然停）——回顾历程、巩固成果、处理分离情感、讨论复发预警与未来求助路径。"
)
declare -a FAILURE_MODES=(
  "**「跳过概念化，直接套手册技术」**：把 DSM 标签当治疗计划——触发原因是把诊断误当成对来访者的完整理解。避免：诊断后必问「什么在维持、资源在哪、从哪切入阻力最小」。"
  "**「治疗惯性 / 没有结案」**：一直做下去，早已偏离目标也不停——触发原因是不做定期回看与结果监测。避免：定期（如每 8–12 次）回看计划，长期无进展就重新概念化或转介，而非默认「继续做就会好」。"
  "**「突然终止当结案」**：来访者脱落 / 治疗师草率收尾，丢掉巩固与分离工作——触发原因是不把结案当一个需要时间的阶段。避免：识别结案信号后留出 2–4 次结案会谈。"
  "**「百科式 intake」**：对所有个案都做同等深度的史采集，第一次会谈变成审讯——后果是关系还没建立就把来访者问跑了。避免：intake 聚焦「与当下问题真正相关」的史。"
  "**CLI 化暗示**：抽进个案弧线自检——「是否签了知情同意（含保密例外）？」「是否有一份成文的、可修订的个案概念化（不是只有 DSM 标签）？」「治疗目标是否和来访者协商一致？」「最近是否回看过计划是否仍成立？」「结案是计划性的、留了阶段，还是突然停的？」"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "workflow-1-walkthrough"
fi
